/*
输入N
将每一栋建筑的数据输入
排序
循环遍历1~N
	sum+=build[i].t1
	Q.push (build[i].t1)
	sum += build[i].t1;
    Q.push(build[i].t1);
    如果sum<=build[i].t2)
        可以多修一栋 
    否则
        sum -= Q.top();
        Q.pop();
输出ans 
*/
#include <bits/stdc++.h>
#define int long long
using namespace std;
int n, sum, ans;
priority_queue <int> Q;
struct Edge {
	int t1, t2;
};
Edge build[150005];
bool cmp (Edge x, Edge y) {
	return x.t2 < y.t2;
}
signed main() {
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> build[i].t1 >> build[i].t2;
	}
	sort (build + 1, build + n + 1, cmp);
	for (int i = 1; i <= n; i++) {
		sum += build[i].t1;
		Q.push (build[i].t1);
		if (sum <= build[i].t2) {
			ans++;
		} else {
			sum -= Q.top();
			Q.pop();
		}
	}
	cout << ans;
	return 0;
}
